1	type Item = { type: string; enchantment?: number; cursed?: boolean };
2	type Scenario = {
3	  customer?: { yearsWithMHPCO?: number };
4	  steps: Array<{ op: string; items?: Item[] }>;
5	};
6	
7	const PROCESSING_FEE = 5;
8	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	const BLOCK_OF_3_PRICE = 60;
17	const BLOCK_ELIGIBLE_TYPES = new Set(["rune", "moonstone"]);
18	const HIGH_ENCHANTMENT_THRESHOLD = 5;
19	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
20	const CURSE_SURCHARGE_RATE = 0.5;
21	const LOYALTY_THRESHOLD_YEARS = 2;
22	const LOYALTY_DISCOUNT_RATE = 0.2;
23	const FIRST_INSURANCE_RATE = 0.1;
24	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
25	
26	function quotePremium(
27	  items: Item[],
28	  yearsWithMHPCO: number,
29	  quoteIndex: number,
30	): number {
31	  const countsByType: Record<string, number> = {};
32	  for (const item of items) {
33	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
34	  }
35	  let policyBase = 0;
36	  for (const [type, count] of Object.entries(countsByType)) {
37	    if (BLOCK_ELIGIBLE_TYPES.has(type) && count === 3) {
38	      policyBase += BLOCK_OF_3_PRICE;
39	    } else {
40	      policyBase += count * BASE_PREMIUM_BY_ITEM_TYPE[type];
41	    }
42	  }
43	  let itemSurcharges = 0;
44	  for (const item of items) {
45	    let rate = 0;
46	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
47	      rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
48	    }
49	    if (item.cursed) {
50	      rate += CURSE_SURCHARGE_RATE;
51	    }
52	    itemSurcharges += rate * BASE_PREMIUM_BY_ITEM_TYPE[item.type];
53	  }
54	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
55	  const loyaltyDiscount =
56	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
57	  const followUpDiscount = quoteIndex >= 1 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
58	  return (
59	    Math.ceil(
60	      policyBase + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount,
61	    ) + PROCESSING_FEE
62	  );
63	}
64	
65	export function processScenario(scenario: unknown): unknown {
66	  const { customer, steps } = scenario as Scenario;
67	  const yearsWithMHPCO = customer?.yearsWithMHPCO ?? 0;
68	  const results = steps.map((step, index) => ({
69	    premium: quotePremium(step.items ?? [], yearsWithMHPCO, index),
70	  }));
71	  return { results };
72	}
